const API_BASE=window.GETOTTS_CONFIG&&window.GETOTTS_CONFIG.API_BASE||"http://localhost:8000/api/v1";const params=new URLSearchParams(window.location.search);let orderId=params.get("id");let secureToken=params.get("token");document.addEventListener("DOMContentLoaded",()=>{if(window.lucide)lucide.createIcons();if(orderId||secureToken){document.getElementById("orderSearch").style.display="none";lookupOrder(orderId||secureToken)}document.getElementById("searchBtn").addEventListener("click",()=>{const input=document.getElementById("orderInput").value.trim().toUpperCase();if(input){orderId=input;lookupOrder(orderId)}});document.getElementById("orderInput").addEventListener("keydown",e=>{if(e.key==="Enter")document.getElementById("searchBtn").click()})});async function lookupOrder(orderNumber){document.getElementById("orderSearch").style.display="none";document.getElementById("orderNotFound").style.display="none";document.getElementById("orderDetails").style.display="none";try{let endpoint=`${API_BASE}/orders/track/${encodeURIComponent(orderNumber)}`;if(secureToken){endpoint=`${API_BASE}/orders/secure/${encodeURIComponent(secureToken)}`}else if(orderNumber.length>20){endpoint=`${API_BASE}/orders/secure/${encodeURIComponent(orderNumber)}`}const headers={};const customerToken=localStorage.getItem("GetOTTs_customer_token");if(customerToken){headers["Authorization"]=`Bearer ${customerToken}`}const resp=await fetch(endpoint,{headers:headers});if(resp.ok){const data=await resp.json();renderOrder(data)}else if(resp.status===404){const localOrder=checkLocalOrders(orderNumber);if(localOrder){renderLocalOrder(localOrder)}else{showNotFound()}}else{const localOrder=checkLocalOrders(orderNumber);if(localOrder){renderLocalOrder(localOrder)}else{showNotFound()}}}catch(e){const localOrder=checkLocalOrders(orderNumber);if(localOrder){renderLocalOrder(localOrder)}else{showNotFound()}}}function checkLocalOrders(orderNumber){const orders=JSON.parse(localStorage.getItem("GetOTTs_orders")||"[]");return orders.find(o=>o.orderNumber===orderNumber)}function renderOrder(data){document.getElementById("orderDetails").style.display="block";setText("oNumber",data.order_number||"—");setText("oDate",formatDate(data.created_at));const amount=data.amount;setText("oAmount",amount!=null?`₹${Number(amount).toLocaleString("en-IN")}`:"—");const payStatus=data.payment_status||"pending";const payPill=document.getElementById("oPayment");if(payPill){payPill.textContent=formatStatusLabel(payStatus);payPill.className=`order-status-pill ${payStatus}`}const delStatus=data.delivery_status||"pending";const delPill=document.getElementById("oDelivery");if(delPill){delPill.textContent=formatStatusLabel(delStatus);delPill.className=`order-status-pill ${delStatus}`}const banner=document.getElementById("orderBanner");const bannerIcon=document.getElementById("bannerIcon");const bannerTitle=document.getElementById("bannerTitle");const bannerSub=document.getElementById("bannerSub");if(delStatus==="delivered"){banner.className="order-banner delivered";bannerIcon.textContent="✅";bannerTitle.textContent="Order Delivered!";bannerSub.textContent="Your credentials are ready below"}else if(payStatus==="paid"){banner.className="order-banner paid";bannerIcon.textContent="💳";bannerTitle.textContent="Payment Confirmed";bannerSub.textContent="Credentials are being prepared…"}else if(payStatus==="failed"){banner.className="order-banner failed";bannerIcon.textContent="❌";bannerTitle.textContent="Payment Failed";bannerSub.textContent="Please try again or contact support"}else{banner.className="order-banner pending";bannerIcon.textContent="⏳";bannerTitle.textContent="Awaiting Payment";bannerSub.textContent="Complete your payment to receive credentials"}const creds=data.credentials_delivered||data.credentials;if(creds&&Object.keys(creds).length>0){showEl("credCard");hideEl("pendingCard");const fields=[{id:"credEmail",key:"email",rowId:"credEmailRow"},{id:"credPassword",key:"password",rowId:"credPasswordRow"},{id:"credProfile",key:"profile",rowId:"credProfileRow"},{id:"credPin",key:"pin",rowId:"credPinRow"},{id:"credOtp",key:"otp",rowId:"credOtpRow"}];fields.forEach(f=>{const el=document.getElementById(f.id);const row=document.getElementById(f.rowId);const val=creds[f.key];if(el&&row){if(val){el.textContent=val;row.style.display="block"}else{row.style.display="none"}}});if(data.expires_at||creds.expires_at){showEl("credExpiryRow");setText("credExpiry",formatDate(data.expires_at||creds.expires_at))}}else{hideEl("credCard");showEl("pendingCard");const pendingTitle=document.getElementById("pendingTitle");const pendingMsg=document.getElementById("pendingMsg");if(payStatus==="paid"&&delStatus!=="delivered"){if(pendingTitle)pendingTitle.textContent="Preparing Your Credentials";if(pendingMsg)pendingMsg.textContent="Payment confirmed! Your credentials are being prepared and will be delivered to your email shortly."}else if(payStatus==="pending"){if(pendingTitle)pendingTitle.textContent="Waiting for Payment";if(pendingMsg)pendingMsg.textContent="Complete your payment to receive your credentials. After payment, delivery is automatic."}}const orderNum=data.order_number||"";setText("tlCreatedTime",formatDate(data.created_at));const tlPaid=document.getElementById("tlPaid");const tlPaidSub=document.getElementById("tlPaidSub");if(payStatus==="paid"||delStatus==="delivered"){tlPaid.className="tl-item done";if(tlPaidSub)tlPaidSub.textContent=data.paid_at?formatDate(data.paid_at):"Payment received"}else if(payStatus==="failed"){tlPaid.className="tl-item";if(tlPaidSub)tlPaidSub.textContent="Payment failed — please retry"}else{tlPaid.className="tl-item active";if(tlPaidSub)tlPaidSub.textContent="Waiting for UPI confirmation"}const tlDelivered=document.getElementById("tlDelivered");const tlDeliveredSub=document.getElementById("tlDeliveredSub");if(delStatus==="delivered"){tlDelivered.className="tl-item done";if(tlDeliveredSub)tlDeliveredSub.textContent=data.delivered_at?formatDate(data.delivered_at):"Sent via email"}const waMsg=encodeURIComponent(`Hi, I need help with my order ${orderNum}`);const helpWaBtn=document.getElementById("helpWaBtn");if(helpWaBtn)helpWaBtn.href=`https://wa.me/919088212294?text=${waMsg}`;const pendingWaBtn=document.getElementById("pendingWaBtn");if(pendingWaBtn)pendingWaBtn.href=`https://wa.me/919088212294?text=${waMsg}`;if(window.lucide)lucide.createIcons()}function renderLocalOrder(order){document.getElementById("orderDetails").style.display="block";setText("oNumber",order.orderNumber||"—");setText("oDate",formatDate(order.date));setText("oAmount",order.amount!=null?`₹${Number(order.amount).toLocaleString("en-IN")}`:"—");const payPill=document.getElementById("oPayment");if(payPill){payPill.textContent="Pending";payPill.className="order-status-pill pending"}const delPill=document.getElementById("oDelivery");if(delPill){delPill.textContent="Pending";delPill.className="order-status-pill pending"}const banner=document.getElementById("orderBanner");banner.className="order-banner pending";document.getElementById("bannerIcon").textContent="⏳";document.getElementById("bannerTitle").textContent="Processing Order";document.getElementById("bannerSub").textContent=`${order.product||"Your order"} — awaiting payment confirmation`;hideEl("credCard");showEl("pendingCard");setText("tlCreatedTime",formatDate(order.date));document.getElementById("tlPaid").className="tl-item active";const waMsg=encodeURIComponent(`Hi, I need help with my order ${order.orderNumber}`);const helpWaBtn=document.getElementById("helpWaBtn");if(helpWaBtn)helpWaBtn.href=`https://wa.me/919088212294?text=${waMsg}`;const pendingWaBtn=document.getElementById("pendingWaBtn");if(pendingWaBtn)pendingWaBtn.href=`https://wa.me/919088212294?text=${waMsg}`;if(window.lucide)lucide.createIcons()}function showNotFound(){document.getElementById("orderNotFound").style.display="block"}function resetSearch(){document.getElementById("orderNotFound").style.display="none";document.getElementById("orderSearch").style.display="block";document.getElementById("orderInput").value="";document.getElementById("orderInput").focus()}function copyText(elementId){const text=document.getElementById(elementId).textContent;navigator.clipboard.writeText(text).then(()=>{const btn=document.getElementById(elementId).parentElement.querySelector(".copy-btn");btn.innerHTML='<span style="font-size:.75rem;color:var(--green-600)">✓ Copied</span>';setTimeout(()=>{btn.innerHTML='<i data-lucide="copy"></i>';if(window.lucide)lucide.createIcons()},2e3)})}function formatDate(dateStr){if(!dateStr)return"—";const d=new Date(dateStr);if(isNaN(d.getTime()))return dateStr;return d.toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"})}function formatStatusLabel(status){if(!status)return"Unknown";return status.charAt(0).toUpperCase()+status.slice(1).replace(/_/g," ")}function setText(id,text){const el=document.getElementById(id);if(el)el.textContent=text}function showEl(id){const el=document.getElementById(id);if(el)el.style.display="block"}function hideEl(id){const el=document.getElementById(id);if(el)el.style.display="none"}